import re
from typing import Dict, Union


class FormParser:
    def parse(self, body: bytes, boundary: str) -> Dict[str, Union[str, bytes]]:
        result = {}
        boundary_bytes = f'--{boundary}'.encode('utf-8')
        parts = body.split(boundary_bytes)
        for part in parts:
            part = part.strip(b'\r\n')
            if not part or part == b'--':
                continue
            if b'\r\n\r\n' in part:
                header_bytes, content = part.split(b'\r\n\r\n', 1)
                header = header_bytes.decode('utf-8', errors='replace')
                name = self._extract_name(header)
                if name:
                    # Check if it's a file upload
                    if 'filename=' in header:
                        result[name] = content  # Keep as bytes
                    else:
                        result[name] = content.decode('utf-8')
        return result

    def _extract_name(self, header: str) -> str:
        match = re.search(r'name="([^"]+)"', header)
        return match.group(1) if match else ''
